// Outerクラスの定義
public class Outer {
    private int value = 10;

    // 1. staticネストクラス
    static class StaticNested {
        // showメソッドの定義
        void show() {
            // value にアクセス不可（staticなので）
            System.out.println("static nested");
        }
    }

    // 2. メンバークラス（inner class）
    // Innerクラスの定義
    class Inner {
        // showメソッドの定義
        void show() {
            // 外部クラスのフィールドにアクセス可能
            System.out.println("inner: " + value);
        }
    }

    void method() {
        // 3. ローカルクラス
        // Localクラスの定義
        class Local {
            void show() {
                System.out.println("local: " + value);
            }
        }
        new Local().show();

        // 4. 匿名クラス
        Runnable r = new Runnable() {
            @Override
            public void run() {
                System.out.println("anonymous: " + value);
            }
        };
        r.run();
    }
}

public class Outer {
    private static int staticVal = 100;
    private int instanceVal = 200;

    // staticネストクラス
    static class StaticNested {
        void show() {
            System.out.println(staticVal);    // ✅ staticメンバーにアクセス可
            // System.out.println(instanceVal); // ❌ インスタンスメンバーは不可
        }

        static void staticMethod() {
            System.out.println("static nested static method");
        }
    }
}

public class Main {
    public static void main(String[] args) {
        // staticネストクラスのインスタンス化
        // 外部クラスのインスタンスは不要
        Outer.StaticNested sn = new Outer.StaticNested();
        sn.show();

        // staticメソッドの呼び出し
        Outer.StaticNested.staticMethod();
    }
}

// Outerクラスの定義
public class Outer {
    private int value = 42;

    // Innerクラスの定義
    class Inner {
        private int value = 99;

        // showメソッドの定義
        void show() {
            System.out.println(value);            // 99（Inner.this.value）
            System.out.println(this.value);        // 99（this = Inner）
            System.out.println(Outer.this.value);  // 42（外部クラス参照）
        }
    }
}

// Mainクラスの定義
public class Main {
    // mainメソッドの定義
    public static void main(String[] args) {
        // メンバークラスのインスタンス化
        // 外部クラスのインスタンスが必要！
        Outer outer = new Outer();
        Outer.Inner inner = outer.new Inner();
        //                    ↑ outer.new の構文に注意
        inner.show();

        // 1行で書く場合
        Outer.Inner inner2 = new Outer().new Inner();
    }
}

