public class Outer {
    private String name = "Outer";

    void process(String prefix) {
        int count = 5;  // 実質的にfinal（再代入されない）

        // ローカルクラスの定義
        class Helper {
            void execute() {
                // 外部クラスのフィールドにアクセス可
                System.out.println(name);
                // メソッドのローカル変数にアクセス可
                // （ただし実質的にfinal）
                System.out.println(prefix + count);
            }
        }

        // ローカルクラスのインスタンス化
        Helper h = new Helper();
        h.execute();

        // count = 10; // これがあるとHelper内のcountがコンパイルエラー
    }
}

